              </Button>
            </div>
          )}

          <div ref={bottomRef} />
        </div>
      </div>

      {/* Guided modal — shown when KAEL has choices and it hasn't been dismissed */}
      {showModal && lastKaelMsg && (
        <KaelGuidedModal
          question={extractQuestion(lastKaelMsg.content)}
          choices={lastKaelMsg.choices!}
          onSelect={sendMessage}
