"use client"

import { useEffect, useRef, useState } from "react"
import { Sparkles, PenLine, ArrowRight, ChevronLeft } from "lucide-react"
import { cn } from "@/lib/utils"

interface KaelGuidedModalProps {
  question: string
  choices: string[]
  onSelect: (choice: string) => void
  onDismiss: () => void
  onSkip?: () => void
}

export function KaelGuidedModal({
  question,
  choices,
  onSelect,
  onDismiss,
  onSkip,
}: KaelGuidedModalProps) {
  const limited = choices.slice(0, 4)
  const [hovered, setHovered] = useState<number | null>(null)
  const [mode, setMode] = useState<"choices" | "custom">("choices")
  const [customText, setCustomText] = useState("")
  const inputRef = useRef<HTMLTextAreaElement>(null)

  // Keyboard shortcuts in "choices" mode
  useEffect(() => {
    if (mode !== "choices") return
    function onKey(e: KeyboardEvent) {
      const target = e.target as HTMLElement
      if (target.tagName === "TEXTAREA" || target.tagName === "INPUT") return
      const num = parseInt(e.key)
      if (!isNaN(num) && num >= 1 && num <= limited.length) {
        e.preventDefault()
        onSelect(limited[num - 1])
      }
      if (e.key === "Escape") onDismiss()
    }
    window.addEventListener("keydown", onKey)
    return () => window.removeEventListener("keydown", onKey)
  }, [mode, limited, onSelect, onDismiss])

  // Focus input when switching to custom mode
  useEffect(() => {
    if (mode === "custom") {
      setTimeout(() => inputRef.current?.focus(), 50)
    }
  }, [mode])

  function handleCustomSend() {
    const text = customText.trim()
    if (!text) return
    onSelect(text)
  }

  function handleCustomKeyDown(e: React.KeyboardEvent) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault()
      handleCustomSend()
    }
    if (e.key === "Escape") setMode("choices")
  }

  return (
    <div className="fixed inset-x-0 bottom-0 z-40 flex justify-center px-4 pb-5 pointer-events-none">
      <div
        className="w-full max-w-lg pointer-events-auto"
        style={{
          animation: "kaelModalIn 0.22s cubic-bezier(0.16, 1, 0.3, 1) both",
        }}
      >
        <div className="bg-zinc-950 border border-zinc-800 rounded-2xl shadow-2xl overflow-hidden ring-1 ring-white/5">

          {/* Header */}
          <div className="flex items-center justify-between px-5 py-3 border-b border-zinc-800/80">
            <div className="flex items-center gap-2">
              <div className="h-5 w-5 rounded-md bg-primary/20 flex items-center justify-center">
                <Sparkles className="h-3 w-3 text-primary" />
              </div>
              <span className="text-[11px] font-semibold text-zinc-400 tracking-widest uppercase">
                KAEL
              </span>
            </div>
            {mode === "custom" && (
              <button
                onClick={() => setMode("choices")}
                className="flex items-center gap-1 text-xs text-zinc-500 hover:text-zinc-300 transition-colors"
              >
                <ChevronLeft className="h-3 w-3" />
                Voir les suggestions
              </button>
            )}
          </div>

          {/* Question */}
          {question && (
            <div className="px-5 pt-4 pb-3">
              <p className="text-sm text-zinc-200 leading-relaxed font-medium">{question}</p>
            </div>
          )}

          {/* Choices mode */}
          {mode === "choices" && (
            <div className="px-4 pb-3 space-y-1.5">
              {limited.map((choice, i) => (
                <button
                  key={i}
                  onClick={() => onSelect(choice)}
                  onMouseEnter={() => setHovered(i)}
                  onMouseLeave={() => setHovered(null)}
                  className={cn(
                    "w-full flex items-center gap-3 px-4 py-3 rounded-xl text-left transition-all duration-100",
                    "border group",
                    hovered === i
                      ? "bg-primary/10 border-primary/30 text-white"
                      : "bg-zinc-900 border-zinc-800 text-zinc-300 hover:bg-zinc-800/80 hover:border-zinc-700"
                  )}
                >
                  <span
                    className={cn(
                      "shrink-0 w-6 h-6 rounded-lg flex items-center justify-center text-xs font-bold tabular-nums",
                      hovered === i
                        ? "bg-primary/20 text-primary"
                        : "bg-zinc-800 text-zinc-500 group-hover:bg-zinc-700"
                    )}
                  >
                    {i + 1}
                  </span>
                  <span className="text-sm leading-snug flex-1">{choice}</span>
                  {hovered === i && (
                    <ArrowRight className="h-3.5 w-3.5 text-primary/60 shrink-0" />
                  )}
                </button>
              ))}
            </div>
          )}

          {/* Custom input mode */}
          {mode === "custom" && (
            <div className="px-4 pb-4">
              <div className="relative rounded-xl border border-zinc-700 bg-zinc-900 overflow-hidden focus-within:border-primary/40 focus-within:ring-1 focus-within:ring-primary/20 transition-all">
                <textarea
                  ref={inputRef}
                  value={customText}
                  onChange={(e) => setCustomText(e.target.value)}
                  onKeyDown={handleCustomKeyDown}
                  placeholder="Votre réponse personnalisée…"
                  rows={2}
                  className="w-full bg-transparent px-4 pt-3 pb-10 text-sm text-zinc-100 placeholder-zinc-600 resize-none outline-none leading-relaxed"
                />
                <div className="absolute bottom-2 right-2 flex items-center gap-2">
                  <span className="text-[10px] text-zinc-600">Entrée pour envoyer</span>
                  <button
                    onClick={handleCustomSend}
                    disabled={!customText.trim()}
                    className={cn(
                      "flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium transition-all",
                      customText.trim()
                        ? "bg-primary text-primary-foreground hover:bg-primary/90"
                        : "bg-zinc-800 text-zinc-600 cursor-not-allowed"
                    )}
                  >
                    Envoyer
                    <ArrowRight className="h-3 w-3" />
                  </button>
                </div>
              </div>
            </div>
          )}

          {/* Footer */}
          <div className="flex items-center justify-between px-5 py-3 border-t border-zinc-800/80">
            {mode === "choices" ? (
              <>
                <button
                  onClick={() => setMode("custom")}
                  className="flex items-center gap-1.5 text-xs text-zinc-500 hover:text-zinc-300 transition-colors"
                >
                  <PenLine className="h-3 w-3" />
                  Répondre librement
                </button>
                <div className="flex items-center gap-3">
                  {onSkip && (
                    <button
                      onClick={onSkip}
                      className="text-xs text-zinc-600 hover:text-zinc-400 transition-colors"
                    >
                      Passer
                    </button>
                  )}
                  <span className="text-[10px] text-zinc-700">
                    {limited.length > 1 ? `1–${limited.length}` : "1"} · Échap
                  </span>
                </div>
              </>
            ) : (
              <span className="text-[10px] text-zinc-600">Maj+Entrée pour sauter une ligne</span>
            )}
          </div>
        </div>
      </div>

      <style jsx>{`
        @keyframes kaelModalIn {
          from {
            opacity: 0;
            transform: translateY(16px) scale(0.98);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }
      `}</style>
    </div>
  )
}

