- Si un fichier structuré est fourni → commence par "J'ai analysé [nom du fichier]." et extrais les points clés
- Ne jamais dire "Je suis une IA" ou disclaimers inutiles
${isFirstMessage && !hasFiles ? "\nC'est le premier message — sois direct, lance la conversation." : ""}
${hasFiles ? "\nDes fichiers ont été fournis — commence par les analyser avant de poser des questions." : ""}

RÈGLES CRITIQUES POUR LES CHOICES :
- Les choices sont des RÉPONSES COURTES que l'utilisateur peut sélectionner en 1 clic, PAS des questions
- Chaque choice = une réponse possible à la question posée dans "message"
- Format : phrase courte affirmative, 4-10 mots max (ex: "Réduire les coûts de production", "Atteindre les PME françaises")
- JAMAIS de "?" dans un choice — ce ne sont pas des questions
- Les choices doivent être directement sélectionnables et couvrir les cas les plus probables

Réponds en JSON:
{
  "message": "question claire et directe en français (1 seule question à la fin)",
  "choices": ["Réponse courte 1", "Réponse courte 2", "Réponse courte 3"],
  "recommendedLab": "NOM_DU_LAB",
  "isComplete": false
}
choices OBLIGATOIRE (2-4 réponses courtes). isComplete: true uniquement quand vision + problème + cible sont établis.`

  // Build messages — images go into content array for vision
  const userContent: OpenAI.Chat.ChatCompletionContentPart[] = [
    { type: "text", text: userInput || (hasFiles ? "Voici les fichiers du projet." : "") },
    ...imageFiles.map((f): OpenAI.Chat.ChatCompletionContentPart => ({
      type: "image_url",
      image_url: { url: f.dataUrl!, detail: "high" },
    })),
  ]

  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    { role: "system", content: system },
    ...history.map((m) => ({
      role: (m.role === "expert" ? "assistant" : "user") as "user" | "assistant",
      content: m.content,
    })),
    { role: "user", content: userContent },
  ]

  const response = await getOpenAI().chat.completions.create(
    {
      model: "gpt-4o",
      max_tokens: 1024,
      response_format: { type: "json_object" },
      messages,
    },
    { timeout: 28000 } // 28s server-side timeout (before 30s client timeout)
  )

  const text = response.choices[0]?.message?.content ?? ""
  try {
    const parsed = JSON.parse(text) as KAELResponse
    // Ensure message is always a string (prevents runtime crash in Markdown renderer)
    if (!parsed.message || typeof parsed.message !== "string") {
      return {
        message: "J'ai analysé votre fichier. Pouvez-vous préciser quel problème principal ce projet cherche à résoudre ?",
        choices: parsed.choices ?? ["Expliquer le problème", "Décrire la cible", "Partager un brief complet"],
      }
    }
    return parsed
  } catch {
    return {
      message: "Intéressant ! Quel problème concret ce projet cherche-t-il à résoudre ?",
      choices: ["Expliquer le problème", "Décrire la cible", "Partager un brief complet"],
    }
  }
}

import OpenAI from "openai"

let _openai: OpenAI | null = null

function getOpenAI(): OpenAI {
  if (!_openai) {
    _openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY! })
  }
  return _openai
}

