"use client"

import { useState, useRef, useEffect, useCallback } from "react"
import { useRouter } from "next/navigation"
import { Button } from "@/components/ui/button"
import { Textarea } from "@/components/ui/textarea"
import { Logo } from "@/components/ui/logo"
import { useAutoResize } from "@/hooks/use-auto-resize"
import { useSpeech } from "@/hooks/use-speech"
import { Markdown } from "@/components/ui/markdown"
import { KaelGuidedModal } from "@/components/kael/kael-guided-modal"
import {
  Send,
  Mic,
  MicOff,
  Paperclip,
  Loader2,
  Sparkles,
  ArrowRight,
  CheckCircle,
} from "lucide-react"
import type { ChatMessage, ConfirmedAspect } from "@/lib/claude"
import type { ExtractedFile } from "@/hooks/use-file-extract"
import { extractFile } from "@/hooks/use-file-extract"
import { cn } from "@/lib/utils"

declare global {
  interface Window {
    SpeechRecognition: any
    webkitSpeechRecognition: any
  }
}

/** Extract the last interrogative sentence from a KAEL message for the modal header */
function extractQuestion(content: string): string {
  const clean = content.replace(/\*\*/g, "").replace(/\*/g, "").trim()
  const sentences = clean.split(/(?<=[.!?])\s+|\n+/).filter(Boolean)
  const question = sentences.slice().reverse().find((s) => s.includes("?"))
  if (question && question.length <= 240) return question.trim()
  return clean.length > 200 ? clean.slice(-200).trim() : clean
}

export default function OnboardingPage({ params }: { params: { id: string } }) {
  const dossierId = params.id
  const router = useRouter()
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [input, setInput] = useState("")
  const [isLoading, setIsLoading] = useState(false)
  const [isExtracting, setIsExtracting] = useState(false)
  const [dossierName, setDossierName] = useState("")
  const [extractedFiles, setExtractedFiles] = useState<ExtractedFile[]>([])
  const [isComplete, setIsComplete] = useState(false)
  const [recommendedLab, setRecommendedLab] = useState<string | null>(null)
  const [confirmedAspects, setConfirmedAspects] = useState<ConfirmedAspect[]>([])
  const [error, setError] = useState<string | null>(null)
  const [dismissedMsgId, setDismissedMsgId] = useState<string | null>(null)
  const bottomRef = useRef<HTMLDivElement>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)
  const initialized = useRef(false)
  const textareaRef = useAutoResize(input)

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [messages])

  useEffect(() => {
    if (initialized.current) return
    initialized.current = true
    initOnboarding()
  }, [dossierId])

  async function initOnboarding() {
    setIsLoading(true)
    try {
      const res = await fetch(`/api/dossiers/${dossierId}/onboarding`, {
        signal: AbortSignal.timeout(15000),
      })
      if (!res.ok) throw new Error(`Erreur ${res.status}`)
      const data = await res.json()
      setDossierName(data.dossier?.name ?? "votre projet")

      if (data.messages && data.messages.length > 0) {
        setMessages(data.messages)
        if (data.confirmedAspects) setConfirmedAspects(data.confirmedAspects)
      } else {
        const name = data.dossier?.name ?? "votre projet"
        const welcomeMsg: ChatMessage = {
          id: crypto.randomUUID(),
          role: "expert",
          content: `Bonjour, je suis KAEL. Je vais vous aider à structurer "${name}" en 4 étapes : problème, cible, résultat attendu, contrainte principale.\n\nCommençons : décrivez en 1-2 phrases le problème concret que ce projet cherche à résoudre.`,
          timestamp: new Date().toISOString(),
          choices: [
            "Améliorer la productivité d'une équipe ou d'un process",
            "Faciliter l'accès à un service pour un public mal servi",
            "Réduire un coût ou une friction significative",
            "Saisir une opportunité de marché non exploitée",
          ],
        }
        setMessages([welcomeMsg])
      }
    } catch (err) {
      console.error("[initOnboarding]", err)
      const welcomeMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: "expert",
        content: `Bonjour, je suis KAEL. Décrivez en 1-2 phrases le problème concret que ce projet cherche à résoudre.`,
        timestamp: new Date().toISOString(),
        choices: [
          "Améliorer la productivité d'une équipe ou d'un process",
          "Faciliter l'accès à un service pour un public mal servi",
          "Réduire un coût ou une friction significative",
          "Saisir une opportunité de marché non exploitée",
        ],
      }
      setMessages([welcomeMsg])
    } finally {
      setIsLoading(false)
    }
  }

  async function sendMessage(text: string) {
    const hasContent = text.trim() || extractedFiles.length > 0
    if (!hasContent || isLoading) return

    const attachmentsMeta = extractedFiles.map((f) => ({ name: f.name, type: f.type, size: f.size }))
    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: "user",
      content: text.trim() || `📎 ${extractedFiles.map((f) => f.name).join(", ")}`,
      timestamp: new Date().toISOString(),
      attachments: attachmentsMeta.length > 0 ? attachmentsMeta : undefined,
    }
    setMessages((prev) => [...prev, userMsg])
    setInput("")

    const fileContexts = extractedFiles.map((f) => ({
      name: f.name,
      kind: f.kind,
      content: f.content,
      dataUrl: f.kind === "image" ? f.dataUrl : undefined,
    }))
    setExtractedFiles([])
    setError(null)
    setIsLoading(true)

    const controller = new AbortController()
    const timeout = setTimeout(() => controller.abort(), 30000)

    try {
      const res = await fetch(`/api/dossiers/${dossierId}/onboarding`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: text.trim(),
          attachments: attachmentsMeta,
          files: fileContexts,
        }),
        signal: controller.signal,
      })

      if (!res.ok) {
        const errData = await res.json().catch(() => ({}))
        throw new Error(errData.error ?? `Erreur serveur ${res.status}`)
      }

      const data = await res.json()
      if (data.messages) setMessages(data.messages)
      if (data.recommendedLab) setRecommendedLab(data.recommendedLab)
      if (data.confirmedAspects) setConfirmedAspects(data.confirmedAspects)
      if (data.isComplete) setIsComplete(true)
    } catch (err) {
      const msg =
        err instanceof Error
          ? err.name === "AbortError"
            ? "Délai dépassé — réessaie"
            : err.message
          : "Erreur inconnue"
      setError(msg)
      setMessages((prev) => prev.filter((m) => m.id !== userMsg.id))
    } finally {
      clearTimeout(timeout)
      setIsLoading(false)
    }
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) {
      sendMessage(input)
    }
  }

  const handleVoiceResult = useCallback((transcript: string) => {
    setInput((prev) => (prev ? prev + " " + transcript : transcript))
  }, [])

  const { isListening, toggle: toggleVoice, interim } = useSpeech({ onResult: handleVoiceResult })

  async function handleFileChange(e: React.ChangeEvent<HTMLInputElement>) {
    const files = Array.from(e.target.files ?? [])
    e.target.value = ""
    if (files.length === 0) return
    setIsExtracting(true)
    try {
      const results = await Promise.all(files.map(extractFile))
      setExtractedFiles((prev) => [...prev, ...results])
    } finally {
      setIsExtracting(false)
    }
  }

  function handleEnterWorkspace() {
    router.push(`/dossiers/${dossierId}`)
  }

  // Compute whether the guided modal should be shown
  const lastKaelMsg = [...messages].reverse().find((m) => m.role === "expert")
  const showModal =
    !isLoading &&
    !isComplete &&
    !!lastKaelMsg?.choices?.length &&
    lastKaelMsg.id !== dismissedMsgId

  function handleModalDismiss() {
    if (lastKaelMsg) setDismissedMsgId(lastKaelMsg.id)
    setTimeout(() => textareaRef.current?.focus(), 80)
  }

  return (
    <div className="h-dvh overflow-hidden flex flex-col bg-background">
      {/* Header */}
      <header className="border-b px-6 py-3 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-3">
          <Logo size="sm" />
          <span className="text-muted-foreground text-sm">·</span>
          <span className="text-sm font-medium truncate max-w-[200px]">{dossierName}</span>
        </div>
        <div className="flex items-center gap-2">
          {isComplete && (
            <Button size="sm" onClick={handleEnterWorkspace} className="gap-2">
              <CheckCircle className="h-4 w-4" />
              Entrer dans le workspace
              <ArrowRight className="h-4 w-4" />
            </Button>
          )}
          {!isComplete && (
            <Button
              variant="ghost"
              size="sm"
              onClick={handleEnterWorkspace}
              className="text-muted-foreground text-xs"
            >
              Passer cette étape
            </Button>
          )}
        </div>
      </header>

      {/* Chat area — extra bottom padding when modal is visible */}
      <div
        className={cn(
          "flex-1 overflow-y-auto px-4 md:px-0 py-6 min-h-0 transition-all duration-200",
          showModal ? "pb-52" : "pb-6"
        )}
      >
        <div className="max-w-2xl mx-auto space-y-5">
          {/* Intro badge + progress */}
          <div className="flex flex-col items-center gap-3">
            <div className="flex items-center gap-2 text-xs text-muted-foreground bg-muted/60 rounded-full px-3 py-1.5">
              <Sparkles className="h-3 w-3" />
              KAEL · Orchestrateur Central
            </div>
            <OnboardingProgress confirmedAspects={confirmedAspects} />
          </div>

          {messages.map((msg) => (
            <div
              key={msg.id}
              className={cn(
                "flex flex-col gap-2",
                msg.role === "user" ? "items-end" : "items-start"
              )}
            >
              <div
                className={cn(
                  "max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed",
                  msg.role === "expert"
                    ? "bg-muted text-foreground rounded-tl-sm"
                    : "bg-primary text-primary-foreground rounded-tr-sm"
                )}
              >
                <Markdown invert={msg.role !== "expert"}>{msg.content}</Markdown>
                {msg.attachments && msg.attachments.length > 0 && (
                  <div className="mt-2 flex flex-wrap gap-1">
                    {msg.attachments.map((a, i) => (
                      <span key={i} className="text-xs opacity-70 bg-black/10 rounded px-1.5 py-0.5">
                        📎 {a.name}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}

          {isLoading && (
            <div className="flex items-start gap-2">
              <div className="bg-muted rounded-2xl rounded-tl-sm px-4 py-3">
                <div className="flex gap-1">
                  <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/50 animate-bounce [animation-delay:0ms]" />
                  <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/50 animate-bounce [animation-delay:150ms]" />
                  <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/50 animate-bounce [animation-delay:300ms]" />
                </div>
              </div>
            </div>
          )}

          {error && (
            <div className="flex items-center gap-2 text-sm text-destructive bg-destructive/10 border border-destructive/20 rounded-xl px-4 py-3">
              <span className="shrink-0">⚠</span>
              {error}
              <button
                onClick={() => setError(null)}
                className="ml-auto text-xs underline opacity-70 hover:opacity-100"
              >
                Fermer
              </button>
            </div>
          )}

          {isComplete && recommendedLab && (
            <div className="border border-primary/30 rounded-2xl p-5 bg-primary/5 text-center space-y-3">
              <CheckCircle className="h-8 w-8 text-primary mx-auto" />
              <p className="font-semibold">Votre projet est prêt à démarrer !</p>
              <p className="text-sm text-muted-foreground">
                LAB recommandé :{" "}
                <span className="font-medium text-foreground">{recommendedLab}</span>
              </p>
              <Button onClick={handleEnterWorkspace} className="gap-2">
                Entrer dans le workspace
                <ArrowRight className="h-4 w-4" />
              </Button>
            </div>
          )}

          <div ref={bottomRef} />
        </div>
      </div>

      {/* Guided modal — shown when KAEL has choices and it hasn't been dismissed */}
      {showModal && lastKaelMsg && (
        <KaelGuidedModal
          question={extractQuestion(lastKaelMsg.content)}
          choices={lastKaelMsg.choices!}
          onSelect={sendMessage}
          onDismiss={handleModalDismiss}
          onSkip={handleEnterWorkspace}
        />
      )}

      {/* Free-text input — hidden when modal active OR onboarding complete */}
      {!showModal && !isComplete && (
        <div className="border-t px-4 py-4 shrink-0">
          <div className="max-w-2xl mx-auto">
            {isExtracting && (
              <div className="flex items-center gap-2 text-xs text-muted-foreground mb-2">
                <Loader2 className="h-3 w-3 animate-spin" />
                Extraction du contenu en cours…
              </div>
            )}
            {extractedFiles.length > 0 && (
              <div className="flex flex-wrap gap-1.5 mb-2">
                {extractedFiles.map((f, i) => (
                  <div
                    key={i}
                    className={cn(
                      "flex items-center gap-1 text-xs rounded-md px-2 py-1 border",
                      f.kind === "image"
                        ? "bg-blue-500/10 border-blue-500/30 text-blue-400"
                        : f.kind === "text"
                        ? "bg-emerald-500/10 border-emerald-500/30 text-emerald-400"
                        : "bg-muted border-border"
                    )}
                    title={
                      f.kind === "text"
                        ? `${f.content?.length ?? 0} caractères extraits`
                        : f.kind
                    }
                  >
                    <Paperclip className="h-3 w-3 shrink-0" />
                    <span className="max-w-[120px] truncate">{f.name}</span>
                    <span className="opacity-60">
                      {f.kind === "image" ? "🖼" : f.kind === "text" ? "✓" : "?"}
                    </span>
                    <button
                      onClick={() => setExtractedFiles((prev) => prev.filter((_, j) => j !== i))}
                      className="ml-0.5 hover:text-destructive"
                    >
                      ×
                    </button>
                  </div>
                ))}
              </div>
            )}
            <div className="flex items-end gap-2">
              <div className="flex-1 relative">
                <Textarea
                  ref={textareaRef}
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={handleKeyDown}
                  placeholder="Décrivez votre projet, partagez vos idées, ajoutez des fichiers…"
                  className="min-h-[52px] resize-none pr-2 text-sm rounded-2xl py-3.5 bg-muted/40 border-muted focus:border-primary/50 overflow-hidden"
                  rows={1}
                  disabled={isLoading}
                />
                {interim && (
                  <p className="px-3 pt-1 pb-0.5 text-xs text-muted-foreground/60 italic truncate">
                    {interim}
                  </p>
                )}
              </div>
              <div className="flex items-center gap-1.5 shrink-0">
                <input
                  ref={fileInputRef}
                  type="file"
                  multiple
                  className="hidden"
                  onChange={handleFileChange}
                />
                <button
                  onClick={() => fileInputRef.current?.click()}
                  className="p-2.5 rounded-xl hover:bg-muted transition-colors text-muted-foreground hover:text-foreground"
                  title="Joindre des fichiers"
                >
                  <Paperclip className="h-4 w-4" />
                </button>
                <button
                  onClick={toggleVoice}
                  className={cn(
                    "p-2.5 rounded-xl transition-colors",
                    isListening
                      ? "bg-red-500/10 text-red-500"
                      : "hover:bg-muted text-muted-foreground hover:text-foreground"
                  )}
                  title="Saisie vocale"
                >
                  {isListening ? (
                    <MicOff className="h-4 w-4" />
                  ) : (
                    <Mic className="h-4 w-4" />
                  )}
                </button>
                <Button
                  onClick={() => sendMessage(input)}
                  disabled={
                    (!input.trim() && extractedFiles.length === 0) || isLoading || isExtracting
                  }
                  className="h-10 w-10 p-0 rounded-xl"
                >
                  {isLoading ? (
                    <Loader2 className="h-4 w-4 animate-spin" />
                  ) : (
                    <Send className="h-4 w-4" />
                  )}
                </Button>
              </div>
            </div>
            <p className="text-[10px] text-muted-foreground mt-1.5 text-center">
              ⌘+Entrée · Déposez des fichiers, partagez des liens, tout est accepté
            </p>
          </div>
        </div>
      )}
    </div>
  )
}

