    scoreSnapshots: { table: "ScoreSnapshot", fk: "dossierId", type: "hasMany" },
    expertSessions: { table: "ExpertSession", fk: "dossierId", type: "hasMany" },
    auditLogs: { table: "AuditLog", fk: "dossierId", type: "hasMany" },
  },
