  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  async $transaction<T>(arg: ((tx: DbClient) => Promise<T>) | Promise<any>[]): Promise<any> {
    if (Array.isArray(arg)) {
      return Promise.all(arg) as unknown as T
    }
    return arg(this)
  }
}

